Greedy insertion with cost‑based selection: evaluate each order against all existing routes using trial insert‑remove cycles, choose the assign with minimal cost increase; if none accepts, start a new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := 0; jj < len(oris); jj++ {
		bestAssignIdx := -1
		bestDelta := math.Inf(1)
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - oldCost
				if newCost >= 0 && delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = idx
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			} else {
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		if bestAssignIdx != -1 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				ok := dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[newIdx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

