func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestDeltaCost := 0.0
		fallbackAssignIdx := -1
		fallbackExists := false

		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]

			prevCost := assign.Cost

			if assign.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx]) {
				assign.GenRoute()

				if assign.Cost >= 0 {
					deltaCost := assign.Cost - prevCost

					if !fallbackExists || deltaCost < 0 {
						fallbackAssignIdx = assignIdx
						fallbackExists = true
					}

					if deltaCost < bestDeltaCost || bestAssignIdx == -1 {
						bestDeltaCost = deltaCost
						bestAssignIdx = assignIdx
					}
				}

				assign.RemoveShip(total_ship + shipIdx)
				assign.GenRoute()
			}
		}

		targetAssignIdx := -1
		if bestAssignIdx != -1 && bestDeltaCost <= 0 {
			targetAssignIdx = bestAssignIdx
		} else if fallbackExists {
			targetAssignIdx = fallbackAssignIdx
		}

		if targetAssignIdx != -1 {
			dispatch.Assigns[targetAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[targetAssignIdx].GenRoute()
		} else {
			newAssignIdx := dispatch.AssignsLen
			if newAssignIdx < MAXASSIGNS {
				dispatch.Assigns[newAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[newAssignIdx].GenRoute()
				if dispatch.Assigns[newAssignIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newAssignIdx].RemoveShip(total_ship + shipIdx)
					dispatch.Assigns[newAssignIdx].GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
