algorithm:
Greedy randomized adaptive search for each order by evaluating cost increase across all feasible assign positions with randomization and fallback to new empty assign when necessary.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		bestAssignIdx := -1
		bestCostDelta := 1e100

		candidateIndices := make([]int, 0, MAXASSIGNS)

		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen && i != dispatch.AssignsLen {
				continue
			}

			assignPtr := &dispatch.Assigns[i]

			oldCost := assignPtr.Cost

			if !assignPtr.AddShip(shipID, ori, des) {
				continue
			}

			assignPtr.GenRoute()

			newCost := assignPtr.Cost

			if newCost >= 0 {
				delta := newCost - oldCost
				if delta < bestCostDelta {
					bestCostDelta = delta
					bestAssignIdx = i
				}
				candidateIndices = append(candidateIndices, i)
			}

			assignPtr.RemoveShip(shipID)
			assignPtr.GenRoute()
		}

		finalAssignIdx := -1
		if len(candidateIndices) > 0 {
			if bestAssignIdx >= 0 {
				finalAssignIdx = bestAssignIdx
			} else {
				finalAssignIdx = candidateIndices[0]
			}
		}

		if finalAssignIdx < 0 {
			finalAssignIdx = dispatch.AssignsLen
			if finalAssignIdx >= MAXASSIGNS {
				finalAssignIdx = 0
				for k := 0; k < MAXASSIGNS; k++ {
					if dispatch.Assigns[k].Cost < 0 || dispatch.Assigns[k].Cost > dispatch.Assigns[finalAssignIdx].Cost {
						finalAssignIdx = k
					}
				}
			}
		}

		targetAssign := &dispatch.Assigns[finalAssignIdx]
		addSuccess := targetAssign.AddShip(shipID, ori, des)
		if !addSuccess {
			targetAssign.AddShip(shipID, ori, des)
		}
		targetAssign.GenRoute()

		if finalAssignIdx >= dispatch.AssignsLen && finalAssignIdx < MAXASSIGNS {
			dispatch.AssignsLen++
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

