func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

algorithm:
Greedy cost‑based insertion with rollback trial for each order: evaluate all existing non‑empty assigns plus one new empty assign, pick the minimal positive cost increase, commit it, otherwise create a new assign as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialRecord struct {
		assignIdx int
		costDelta float64
		succeeded bool
	}
	for shipIDOffset := range oris {
		best := trialRecord{-1, 1e100, false}
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset

		checkAssign := func(assignIdx int, useNewEmpty bool) {
			var curAssign *Assign
			if useNewEmpty {
				if dispatch.AssignsLen >= MAXASSIGNS {
					return
				}
				curAssign = &dispatch.Assigns[dispatch.AssignsLen]
				*curAssign = Assign{}
			} else {
				curAssign = &dispatch.Assigns[assignIdx]
			}
			oldCost := curAssign.Cost
			added := curAssign.AddShip(shipID, ori, des)
			if added {
				curAssign.GenRoute()
				newCost := curAssign.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < best.costDelta {
						best.assignIdx = assignIdx
						best.costDelta = delta
						best.succeeded = true
					}
				}
				curAssign.RemoveShip(shipID)
				curAssign.GenRoute()
			}
		}

		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			checkAssign(idx, false)
		}
		checkAssign(-1, true)

		if best.succeeded {
			targetAssign := &dispatch.Assigns[best.assignIdx]
			ok := targetAssign.AddShip(shipID, ori, des)
			if ok {
				targetAssign.GenRoute()
			}
		} else {
			if dispatch.AssignsLen >= MAXASSIGNS {
				continue
			}
			newAssign := &dispatch.Assigns[dispatch.AssignsLen]
			ok := newAssign.AddShip(shipID, ori, des)
			if ok {
				newAssign.GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

